import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"The Rundown AI — 2026-05-07","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-07","date":"2026-05-07T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-07-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-07-the-rundown-ai.md","lastUpdated":1779898012000}'),i={name:"research/ai-news/2026-05/2026-05-07-the-rundown-ai.md"};function o(s,e,p,m,u,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-05-07" tabindex="-1">🗞️ The Rundown AI — 2026-05-07 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-07" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-07&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="anthropic-spacex-ai-become-unlikely-compute-partners" tabindex="-1"><a href="https://www.therundown.ai/p/anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Anthropic, SpaceX(AI) become unlikely compute partners</a> <a class="header-anchor" href="#anthropic-spacex-ai-become-unlikely-compute-partners" aria-label="Permalink to &quot;[Anthropic, SpaceX(AI) become unlikely compute partners](https://www.therundown.ai/p/anthropic-spacex-ai-become-unlikely-compute-partners)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-07</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. Just months ago, Elon Musk was posting that Anthropic “hates Western Civilization” and should be renamed “Misanthropic”. Now, he’s renting them his entire Colossus 1 compute cluster.</p><p>The new deal pulls off three things at once: patching Claude&#39;s compute problems, hurting Musk&#39;s nemesis OAI by feeding its biggest rival, and signaling a new compute-landlord business for SpaceXAI even as Grok keeps chasing the frontier.</p><p>In today’s AI rundown:</p><p>Anthropic, SpaceX partner in new compute deal</p><p>Mira Murati speaks out in Musk vs. OpenAI trial</p><p>Use Claude Design’s slide decks feature like a pro</p><p>DeepMind picks EVE Online game as next AI testbed</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>ANTHROPIC &amp; SPACEX</p><p>🔌 <a href="https://www.anthropic.com/news/higher-limits-spacex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Anthropic, SpaceX(AI) partner in new compute deal</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: Anthropic just <a href="https://www.anthropic.com/news/higher-limits-spacex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">signed</a> a deal with SpaceX to lease its Colossus 1, raising Claude usage and putting Musk and Anthropic on one team months after he <a href="https://x.com/elonmusk/status/2027294561467613256?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">said</a> that Anthropic should be called “Misanthropic” and it &quot;hates Western Civilization.&quot;</p><p>The details:</p><p>Anthropic will lease all of Colossus 1, a 300+ MW Memphis supercluster, with more than 220K Nvidia GPUs coming online within the month.</p><p>Anthropic said Claude Code’s 5-hour usage caps are now doubling across paid tiers, with additional increases via API and no more peak-hour restrictions.</p><p>Musk <a href="https://x.com/elonmusk/status/2052076315306864756?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">replied</a> on X that SpaceX will rent compute to “AI companies that are taking the right steps to ensure it is good for humanity.”</p><p>The Information also <a href="https://www.theinformation.com/articles/anthropic-commits-spending-200-billion-googles-cloud-chips?rc=a8sc5q&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">reported</a> yesterday that Anthropic is committing to a $200B, 5 GW compute deal over the next five years with Google Cloud.</p><p>Why it matters: This is a fascinating partnership from several angles. One being Musk taking the ‘enemy of my enemy is my friend’ approach — helping patch OAI’s biggest rival’s glaring compute hole. Another is SpaceXAI (<a href="https://x.com/elonmusk/status/2052105373621121284?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">apparently</a> the new name), moving to providing compute for rivals while still pushing to get Grok near the frontier.</p><p>TOGETHER WITH STRIPE</p><p>🏷️ <a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer">A five-step framework for pricing AI products</a></p><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Pricing AI products means making a series of connected decisions—how you charge, how you match prices to value, and how you adapt as costs and the market shift. Stripe&#39;s new framework outlines 5 steps for pricing AI products.</p><p>In this guide, you’ll learn:</p><p>How AI leaders like Anthropic, Clay, and Vercel approach their pricing</p><p>Strategies to align what you charge with the exact value you deliver</p><p>Steps to pick a pricing model that balances ease of user adoption with repeatable revenue</p><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer">Get the framework</a>.</p><p>ELON MUSK VS. OPENAI TRIAL</p><p>🏛️ <a href="https://www.theverge.com/ai-artificial-intelligence/925338/openai-musk-v-altman-mira-murati?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Mira Murati speaks out in Musk vs. OpenAI trial</a></p><p>Image source: Reuters</p><p>The Rundown: Ex-OpenAI CTO Mira Murati <a href="https://www.theverge.com/ai-artificial-intelligence/925338/openai-musk-v-altman-mira-murati?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">testified</a> Wednesday via video deposition in Elon Musk&#39;s lawsuit against OpenAI, accusing CEO Sam Altman of lying about a model&#39;s safety review, undermining her authority, and pitting execs against one another.</p><p>The details:</p><p>Murati said Altman told her OAI&#39;s legal team cleared a model to skip safety review, which she later verified with counsel Jason Kwon was false.</p><p>She also described Altman giving conflicting directions to different execs, making her role as CTO harder and creating chaos across OAI&#39;s leadership.</p><p>Murati briefly became interim CEO during Altman’s 2023 firing, but said the board process put OpenAI “at risk of falling apart.”</p><p>Former OAI board member Helen Toner also <a href="https://nypost.com/2026/05/06/business/openai-ceo-sam-altman-was-dishonest-caused-chaos-ex-exec-mira-murati-says-in-bombshell-testimony/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">testified</a>, reportedly criticizing Murati as “afraid to stick her neck out” and scared of “blowback for her career”.</p><p>Why it matters: The 2023 board drama is the saga that will never conclude, and Murati’s testimony is a powerful voice to aid Musk’s argument that Altman and co. are untrustworthy. But whether that ultimately means anything related to Musk’s claims of Altman and Brockman “trying to steal a charity” in 2017 is up for the jury to decide.</p><p>AI TRAINING</p><p>👨‍💻 <a href="https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Use Claude Design’s slide decks feature like a pro</a></p><p><a href="https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to use Claude Design to turn your raw data into a useful strategy deck complete with actual insights. Claude Design analyzes what is working and gives concrete recommendations your team can use.</p><p>Step-by-step:</p><p>Start with one CSV or spreadsheet with a messy report (YT channel data, Facebook ads, etc.) and decide what the deck needs to do (like find patterns)</p><p>Open claude.ai/design, choose Slide deck, skip the design system, toggle on speaker notes, and upload your data</p><p>Prompt: “Turn these files into a strategy deck on performance. Analyze the results by item and extract best practices from the data and assets. Use charts, rankings, and concrete recommendations. Match images or creative files to CSV using the filename or matching field. Keep it presentation-ready”</p><p>Generation will take 10-15 minutes. You can export to PowerPoint or Google Slides when it&#39;s ready</p><p>Pro tip: Duplicate the project and upload more data sources for Claude to incorporate into the presentation.</p><p>PRESENTED BY IBM</p><p>🔌 <a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Rewire the C-suite for an AI-first world</a></p><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Most leaders know AI will reshape their business, but few have a clear playbook for how. An IBM Institute of Business Value analysis reveals 5 plays that CEOs must fulfill now for payoffs by 2030.</p><p>To lead in an AI-first landscape, surveyed CEOs suggest:</p><p>Customize your AI mix, not just your AI models</p><p>Hire a Chief AI Officer if you haven’t already</p><p>Orchestrate intelligence —both artificial and human</p><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Get deeper details in the 2026 CEO Study</a>.</p><p>GOOGLE DEEPMIND</p><p>🛸 <a href="https://www.ccpgames.com/news/2026/studio-behind-eve-online-goes-independent-rebrands-as-fenris-creations-enters-research-partnership-with-google-deepmind?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">DeepMind picks EVE Online game as next AI testbed</a></p><p>Image source: Fenris Creations</p><p>The Rundown: Google DeepMind <a href="https://www.ccpgames.com/news/2026/studio-behind-eve-online-goes-independent-rebrands-as-fenris-creations-enters-research-partnership-with-google-deepmind?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">picked up</a> a minority stake in Fenris Creations, a game studio spinoff from CCP Games, which makes the popular EVE Online — with DeepMind set to use the 23-year-old space game as a sandbox for AI research.</p><p>The details:</p><p>EVE Online has run for two decades on a single server where players form corporations, set market prices, and torch six-figure fleets in day-long battles.</p><p>DeepMind&#39;s investment will come with AI agent runs on an offline EVE clone, testing how models reason over long timelines, retain memory, and learn.</p><p>Demis Hassabis cited Atari DQN, AlphaGo, AlphaStar, and SIMA as game-bred DeepMind wins, calling games “the perfect training ground” for AI algorithms.</p><p>Fenris’ CEO pitched EVE as “one of the few environments” where intelligence can be tested “inside something that already behaves like a living world”.</p><p>Why it matters: DeepMind has been here before with Go, Atari, StarCraft, and SIMA, but EVE is not a match to win as much as a 23-year-old living, evolving society to understand. That makes the Fenris deal a natural next step in the shift from game-playing AI to agents that can operate inside less predictable real-life systems.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🧠 <a href="https://memoket.ai/pages/use-cases?utm_source=newsletter&amp;utm_medium=email&amp;utm_campaign=Rundown0507" target="_blank" rel="noreferrer">Memoket</a> - Stop briefing AI from scratch. Memoket captures conversations and remembers context. Try the app for free today*</p><p>🤖 <a href="https://www.rundown.ai/tools/claude-managed-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Claude Managed Agents</a> - Pre-built agent harness with ‘dreaming’ memory</p><p>⚡️ <a href="https://openai.com/index/gpt-5-5-instant/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">GPT 5.5 Instant</a> - OpenAI’s new default model across ChatGPT</p><p>🎧 <a href="https://www.rundown.ai/tools/realtime-tts-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Realtime TTS-2</a> - New voice AI that listens to match user tone and emotion</p><p>*Sponsored Listing</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>Subquadratic <a href="https://subq.ai/how-ssa-makes-long-context-practical?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">debuted</a> SubQ, a model the company claims has a 12M token context window and a 52x speed boost on long tasks at a fraction of the cost over rivals.</p><p>Anthropic <a href="https://claude.com/blog/new-in-claude-managed-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">launched</a> dreaming, outcomes, and multi-agent orchestration for Managed Agents, letting agents study past sessions, grade work, and split complex jobs.</p><p>OpenAI <a href="https://openai.com/index/mrc-supercomputer-networking/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">teamed</a> up with AMD, Intel, NVIDIA, Microsoft, and Broadcom to open-source MRC, a tool that keeps giant AI training runs going when hardware fails mid-session.</p><p>Chinese AI startup DeepSeek is reportedly <a href="https://www.ft.com/content/daaf2e0a-4a0d-4d7c-a85b-445480f6b9c7?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">nearing</a> a new funding round that would value the company at as high as $45B.</p><p>Google <a href="https://blog.google/innovation-and-ai/models-and-research/google-labs/believe-flow-music-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">announced</a> a new partnership with TuneCore parent Believe to put its Flow Music and Lyria 3 Pro model in front of artists.</p><p>COMMUNITY</p><p>🤝 <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Anonymous:</p><p>&quot;I&#39;m recovering from a torn ACL, and my physiotherapist films all of my exercises and sends the videos to me on WhatsApp, narrating the sets/reps and notes on how to perform the exercise properly.</p><p>I uploaded the videos into Gemini and got it to build a prompt for Claude Code, which one-shotted an app that I now use to track sets, reps, weights from last workouts, notes, over multiple months. I can then export this data into a .csv for my physio before we check back in with each other.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-ai-phone-just-jumped-the-line?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">OpenAI’s AI phone just jumped the line</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/gamestop-wild-bid-to-buy-ebay?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">GameStop’s wild bid to buy eBay</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meta-buys-a-humanoid-brain?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Meta buys a humanoid brain</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Use Claude Design’s slide decks feature like a pro</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',102)])])}const d=a(i,[["render",o]]);export{h as __pageData,d as default};
